# Generated by openai (gpt-5.4)
# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any

    options {
        timestamps()
        disableConcurrentBuilds()
        buildDiscarder(logRotator(numToKeepStr: '30'))
        ansiColor('xterm')
    }

    parameters {
        text(
            name: 'ARTIFACT_URLS',
            defaultValue: '',
            description: 'One artifact URL per line. Supports HTTP/HTTPS/S3-style presigned URLs.'
        )
        string(
            name: 'DEPLOY_SERVERS',
            defaultValue: 'prod-app-01.example.com,prod-app-02.example.com',
            description: 'Comma-separated production servers.'
        )
        string(
            name: 'DEPLOY_PATH',
            defaultValue: '/opt/myapp/deployments',
            description: 'Remote path where artifacts will be uploaded.'
        )
        string(
            name: 'SERVICE_NAME',
            defaultValue: 'myapp',
            description: 'Service to restart after deployment.'
        )
        credentials(
            name: 'SSH_CREDENTIALS_ID',
            defaultValue: 'prod-ssh-creds',
            description: 'SSH credentials for production servers.'
        )
        booleanParam(
            name: 'RESTART_SERVICE',
            defaultValue: true,
            description: 'Restart the service after artifacts are uploaded.'
        )
        booleanParam(
            name: 'CLEAN_REMOTE',
            defaultValue: false,
            description: 'Clean remote deploy path before uploading artifacts.'
        )
        booleanParam(
            name: 'VERIFY_CHECKSUMS',
            defaultValue: false,
            description: 'Verify checksums if .sha256 URL exists beside artifact.'
        )
    }

    environment {
        DOWNLOAD_DIR = "${WORKSPACE}/downloads"
        MANIFEST_FILE = "${WORKSPACE}/artifact-manifest.txt"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    def urls = params.ARTIFACT_URLS
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    if (!urls) {
                        error('ARTIFACT_URLS must contain at least one URL.')
                    }

                    def servers = params.DEPLOY_SERVERS
                        .split(',')
                        .collect { it.trim() }
                        .findAll { it }

                    if (!servers) {
                        error('DEPLOY_SERVERS must contain at least one server.')
                    }

                    urls.each { url ->
                        if (!(url ==~ /^(https?|s3):\/\/.+/)) {
                            error("Unsupported artifact URL: ${url}")
                        }
                    }

                    writeFile file: 'validated-urls.txt', text: urls.join('\n') + '\n'
                    writeFile file: 'validated-servers.txt', text: servers.join('\n') + '\n'
                }
            }
        }

        stage('Prepare Workspace') {
            steps {
                sh '''
                    set -eu
                    rm -rf "$DOWNLOAD_DIR"
                    mkdir -p "$DOWNLOAD_DIR"
                    : > "$MANIFEST_FILE"
                '''
            }
        }

        stage('Download Artifacts') {
            steps {
                script {
                    def urls = readFile('validated-urls.txt')
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    urls.eachWithIndex { url, idx ->
                        def safeName = url.tokenize('/').last()
                        if (!safeName || safeName.trim().isEmpty()) {
                            safeName = "artifact-${idx + 1}"
                        }
                        safeName = safeName.replaceAll(/[?#].*$/, '')
                        if (!safeName) {
                            safeName = "artifact-${idx + 1}"
                        }

                        sh """
                            set -euo pipefail
                            url='${url.replace("'", "'\"'\"'")}'
                            file='${safeName.replace("'", "'\"'\"'")}'

                            echo "Downloading \$url -> $DOWNLOAD_DIR/\$file"
                            curl --fail --location --retry 3 --connect-timeout 20 --output "$DOWNLOAD_DIR/\$file" "\$url"

                            if [ ! -s "$DOWNLOAD_DIR/\$file" ]; then
                              echo "Downloaded file is empty: \$file" >&2
                              exit 1
                            fi

                            if [ "${params.VERIFY_CHECKSUMS}" = "true" ]; then
                              checksum_url="\${url}.sha256"
                              checksum_file="$DOWNLOAD_DIR/\${file}.sha256"
                              if curl --fail --location --silent --show-error --output "\$checksum_file" "\$checksum_url"; then
                                cd "$DOWNLOAD_DIR"
                                expected_file="\$(basename "\$checksum_file")"
                                artifact_file="\$(basename "\$file")"
                                if grep -q "\$artifact_file" "\$expected_file"; then
                                  sha256sum -c "\$expected_file"
                                else
                                  expected_sum="\$(awk '{print \$1}' "\$expected_file" | head -n1)"
                                  actual_sum="\$(sha256sum "\$artifact_file" | awk '{print \$1}')"
                                  [ "\$expected_sum" = "\$actual_sum" ]
                                fi
                              else
                                echo "No checksum found for \$url, skipping verification"
                              fi
                            fi

                            sha256sum "$DOWNLOAD_DIR/\$file" | awk '{print \$1}' > "$DOWNLOAD_DIR/\$file.sha256.local"
                            size=\$(stat -c%s "$DOWNLOAD_DIR/\$file" 2>/dev/null || wc -c < "$DOWNLOAD_DIR/\$file")
                            printf "%s|%s|%s|%s\\n" "\$file" "\$url" "\$size" "\$(cat "$DOWNLOAD_DIR/\$file.sha256.local")" >> "$MANIFEST_FILE"
                        """
                    }
                }
            }
        }

        stage('Archive Manifest') {
            steps {
                archiveArtifacts artifacts: 'artifact-manifest.txt,downloads/*.sha256.local', fingerprint: true
            }
        }

        stage('Deploy to Production') {
            steps {
                script {
                    def servers = readFile('validated-servers.txt')
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            sh """
                                set -euo pipefail
                                server='${server.replace("'", "'\"'\"'")}'

                                ssh -o StrictHostKeyChecking=no "\$server" "mkdir -p '${params.DEPLOY_PATH.replace("'", "'\"'\"'")}'"

                                if [ "${params.CLEAN_REMOTE}" = "true" ]; then
                                  ssh -o StrictHostKeyChecking=no "\$server" "find '${params.DEPLOY_PATH.replace("'", "'\"'\"'")}' -mindepth 1 -maxdepth 1 -type f -delete"
                                fi

                                scp -o StrictHostKeyChecking=no "$DOWNLOAD_DIR"/* "\$server":'${params.DEPLOY_PATH.replace("'", "'\"'\"'")}/'

                                ssh -o StrictHostKeyChecking=no "\$server" "
                                  set -e
                                  cd '${params.DEPLOY_PATH.replace("'", "'\"'\"'")}'
                                  if [ -f artifact-manifest.txt ]; then rm -f artifact-manifest.txt; fi
                                "
                                scp -o StrictHostKeyChecking=no "$MANIFEST_FILE" "\$server":'${params.DEPLOY_PATH.replace("'", "'\"'\"'")}/artifact-manifest.txt'

                                if [ "${params.RESTART_SERVICE}" = "true" ]; then
                                  ssh -o StrictHostKeyChecking=no "\$server" "sudo systemctl restart '${params.SERVICE_NAME.replace("'", "'\"'\"'")}' && sudo systemctl is-active '${params.SERVICE_NAME.replace("'", "'\"'\"'")}'"
                                fi
                            """
                        }
                    }
                }
            }
        }

        stage('Post-Deploy Verification') {
            steps {
                script {
                    def servers = readFile('validated-servers.txt')
                        .split(/\r?\n/)
                        .collect { it.trim() }
                        .findAll { it }

                    sshagent(credentials: [params.SSH_CREDENTIALS_ID]) {
                        servers.each { server ->
                            sh """
                                set -euo pipefail
                                server='${server.replace("'", "'\"'\"'")}'

                                ssh -o StrictHostKeyChecking=no "\$server" "
                                  set -e
                                  test -d '${params.DEPLOY_PATH.replace("'", "'\"'\"'")}'
                                  test -f '${params.DEPLOY_PATH.replace("'", "'\"'\"'")}/artifact-manifest.txt'
                                  if [ '${params.RESTART_SERVICE}' = 'true' ]; then
                                    sudo systemctl is-active '${params.SERVICE_NAME.replace("'", "'\"'\"'")}' >/dev/null
                                  fi
                                "
                            """
                        }
                    }
                }
            }
        }
    }

    post {
        always {
            archiveArtifacts artifacts: 'validated-urls.txt,validated-servers.txt', onlyIfSuccessful: false
            cleanWs(deleteDirs: true, notFailBuild: true)
        }
        success {
            echo 'Deployment completed successfully.'
        }
        failure {
            echo 'Deployment failed.'
        }
    }
}